import{_ as a,o as s,c as n,ag as t}from"./chunks/framework.DAY4Zhxq.js";const u=JSON.parse('{"title":"Architecture Overview","description":"","frontmatter":{},"headers":[],"relativePath":"dev/index.md","filePath":"dev/index.md"}'),i={name:"dev/index.md"};function r(o,e,l,c,p,d){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h1><p>Alpaka Desktop is a Tauri v2 desktop application: a single process with a Rust backend and a Vue 3 SPA frontend rendered in WebKitGTK. Frontend and backend communicate exclusively via Tauri IPC.</p><h2 id="high-level-structure" tabindex="-1">High-Level Structure <a class="header-anchor" href="#high-level-structure" aria-label="Permalink to &quot;High-Level Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                      TAURI v2 PROCESS                        │</span></span>
<span class="line"><span>│  ┌────────────────────────┐    ┌───────────────────────────┐ │</span></span>
<span class="line"><span>│  │   Vue 3 Frontend       │    │   Rust Backend            │ │</span></span>
<span class="line"><span>│  │   (WebKitGTK WebView)  │◄──►│   (Tauri Commands)        │ │</span></span>
<span class="line"><span>│  │                        │IPC │                           │ │</span></span>
<span class="line"><span>│  │  Pinia Stores          │    │  commands/    (IPC layer)  │ │</span></span>
<span class="line"><span>│  │  Composables           │    │  services/    (logic)      │ │</span></span>
<span class="line"><span>│  │  Views                 │    │  ollama/      (HTTP)       │ │</span></span>
<span class="line"><span>│  └────────────────────────┘    │  db/          (SQLite)    │ │</span></span>
<span class="line"><span>│                                │  auth/        (keyring)   │ │</span></span>
<span class="line"><span>│                                │  system/      (tray etc.) │ │</span></span>
<span class="line"><span>│                                └───────────────────────────┘ │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>          │                              │</span></span>
<span class="line"><span>          ▼                              ▼</span></span>
<span class="line"><span>  Static Assets (Vite)         Ollama Hosts (HTTP)</span></span></code></pre></div><h2 id="communication-patterns" tabindex="-1">Communication Patterns <a class="header-anchor" href="#communication-patterns" aria-label="Permalink to &quot;Communication Patterns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Direction</th><th>Mechanism</th><th>Used for</th></tr></thead><tbody><tr><td>Frontend → Backend</td><td><code>invoke(&#39;command_name&#39;, payload)</code></td><td>Request/response (CRUD, settings, model ops)</td></tr><tr><td>Backend → Frontend</td><td><code>app.emit(&#39;event:name&#39;, payload)</code> / <code>listen()</code></td><td>Streaming tokens, async progress, health updates</td></tr></tbody></table><h2 id="backend-layering" tabindex="-1">Backend Layering <a class="header-anchor" href="#backend-layering" aria-label="Permalink to &quot;Backend Layering&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>commands/       ← Tauri IPC boundary (thin adapters only — no business logic)</span></span>
<span class="line"><span>    └── services/   ← Business logic (ChatService, PromptService, WebSearchService, LibraryService)</span></span>
<span class="line"><span>            └── ollama/client.rs   ← HTTP client with multi-host routing</span></span>
<span class="line"><span>            └── db/                ← SQLite via rusqlite</span></span>
<span class="line"><span>            └── auth/keyring.rs    ← Secret Service API</span></span></code></pre></div><h2 id="frontend-layering" tabindex="-1">Frontend Layering <a class="header-anchor" href="#frontend-layering" aria-label="Permalink to &quot;Frontend Layering&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>views/          ← Page-level Vue components (ChatPage, ModelsPage, SettingsPage, LaunchPage)</span></span>
<span class="line"><span>    └── composables/    ← Reactive logic units (23 composables)</span></span>
<span class="line"><span>            └── stores/ ← Pinia state (chat, models, hosts, settings, auth)</span></span></code></pre></div><h2 id="key-design-decisions" tabindex="-1">Key Design Decisions <a class="header-anchor" href="#key-design-decisions" aria-label="Permalink to &quot;Key Design Decisions&quot;">​</a></h2><p><strong>Why Tauri v2, not Electron?</strong> Binary size and memory. The Tauri binary is ~8 MB and uses ~60 MB PSS at idle. An Electron equivalent is typically 150–200 MB binary and 300+ MB at idle.</p><p><strong>Why SQLite, not a remote database?</strong> Alpaka Desktop is local-first. All conversation history stays on your machine. The SQLite file lives in the Tauri app data directory (<code>~/.local/share/alpaka-desktop/</code>).</p><p><strong>Why Secret Service for API keys?</strong> Keys stored in SQLite would be readable by any process with access to the file. The Secret Service API provides OS-level access control, the same mechanism used by browsers and password managers.</p><h2 id="full-reference" tabindex="-1">Full Reference <a class="header-anchor" href="#full-reference" aria-label="Permalink to &quot;Full Reference&quot;">​</a></h2><p>The complete internal architecture document (command registry, SQLite schema, ADRs, performance budget) is at <a href="https://github.com/nikoteressi/alpaka-desktop/blob/main/docs/ARCHITECTURE.md" target="_blank" rel="noreferrer"><code>docs/ARCHITECTURE.md</code></a> in the repository.</p>`,16)])])}const m=a(i,[["render",r]]);export{u as __pageData,m as default};
